#!/usr/bin/env python3

import argparse

import pandas as pd


HIGH_CONFIDENCE_CLASS_CODES = {
    "=",
    "c",
    "j",
    "k",
}


def parse_args():
    parser = argparse.ArgumentParser(
        description=(
            "Add gffcompare gene annotations to a transcript count matrix "
            "and sum transcript counts into gene-level counts."
        )
    )

    parser.add_argument(
        "--annotation",
        required=True,
        help=(
            "Transcript annotation table generated by "
            "parse_gffcompare_annotation.py."
        )
    )

    parser.add_argument(
        "--transcript-counts",
        required=True,
        help="Merged transcript count matrix."
    )

    parser.add_argument(
        "--transcript-output",
        required=True,
        help=(
            "Output transcript count matrix containing transcript_id, "
            "stringtie_gene_id, ref_gene_id, gene_name, class_code, "
            "aggregation_gene_id, and sample counts."
        )
    )

    parser.add_argument(
        "--gene-output",
        required=True,
        help="Output gene-level count matrix."
    )

    return parser.parse_args()


def clean_text_column(series: pd.Series) -> pd.Series:
    return (
        series
        .astype("string")
        .str.strip()
        .replace("", pd.NA)
    )


def read_transcript_gene_map(
    annotation_path: str
) -> pd.DataFrame:

    mapping = pd.read_csv(
        annotation_path,
        sep="\t",
        dtype=str,
        keep_default_na=False
    )

    required_columns = [
        "transcript_id",
        "gene_id",
        "ref_gene_id",
        "class_code"
    ]

    missing_columns = [
        column
        for column in required_columns
        if column not in mapping.columns
    ]

    if missing_columns:
        raise ValueError(
            "Annotation file is missing required columns: "
            f"{', '.join(missing_columns)}"
        )

    mapping = mapping.rename(
        columns={
            "gene_id": "stringtie_gene_id"
        }
    )

    # gene_name is optional because older versions of
    # transcript_annotation.tsv may not contain it.
    if "gene_name" not in mapping.columns:
        mapping["gene_name"] = pd.NA

    text_columns = [
        "transcript_id",
        "stringtie_gene_id",
        "ref_gene_id",
        "gene_name",
        "class_code"
    ]

    for column in text_columns:
        mapping[column] = clean_text_column(
            mapping[column]
        )

    mapping = mapping.dropna(
        subset=["transcript_id"]
    )

    duplicate_transcripts = mapping[
        mapping.duplicated(
            subset=["transcript_id"],
            keep=False
        )
    ]

    if not duplicate_transcripts.empty:
        conflicting = (
            duplicate_transcripts
            .groupby("transcript_id")
            .agg(
                gene_count=(
                    "stringtie_gene_id",
                    "nunique"
                ),
                ref_gene_count=(
                    "ref_gene_id",
                    "nunique"
                ),
                class_code_count=(
                    "class_code",
                    "nunique"
                )
            )
        )

        conflicting = conflicting[
            (conflicting["gene_count"] > 1)
            | (conflicting["ref_gene_count"] > 1)
            | (conflicting["class_code_count"] > 1)
        ]

        if not conflicting.empty:
            examples = ", ".join(
                conflicting.index.astype(str)[:10]
            )

            raise ValueError(
                "Some transcript IDs have conflicting annotations. "
                f"Examples: {examples}"
            )

    mapping = mapping.drop_duplicates(
        subset=["transcript_id"],
        keep="first"
    )

    high_confidence_reference = (
        mapping["class_code"].isin(
            HIGH_CONFIDENCE_CLASS_CODES
        )
        & mapping["ref_gene_id"].notna()
    )

    # Known transcripts and high-confidence novel isoforms are
    # aggregated using the corresponding Ensembl gene ID.
    #
    # Transcripts without a reliable reference-gene assignment
    # retain their original StringTie MSTRG gene ID.
    mapping["aggregation_gene_id"] = (
        mapping["stringtie_gene_id"]
    )

    mapping.loc[
        high_confidence_reference,
        "aggregation_gene_id"
    ] = mapping.loc[
        high_confidence_reference,
        "ref_gene_id"
    ]

    missing_aggregation_ids = (
        mapping["aggregation_gene_id"].isna()
    )

    if missing_aggregation_ids.any():
        missing_count = int(
            missing_aggregation_ids.sum()
        )

        print(
            f"Warning: {missing_count} annotated transcripts have "
            "neither a reference gene ID nor a StringTie gene ID."
        )

    return mapping[
        [
            "transcript_id",
            "stringtie_gene_id",
            "ref_gene_id",
            "gene_name",
            "class_code",
            "aggregation_gene_id"
        ]
    ]


def main():
    args = parse_args()

    mapping = read_transcript_gene_map(
        args.annotation
    )

    counts = pd.read_csv(
        args.transcript_counts,
        sep="\t"
    )

    if "Name" not in counts.columns:
        raise ValueError(
            "Transcript count matrix must contain a column named 'Name'."
        )

    counts = counts.rename(
        columns={
            "Name": "transcript_id"
        }
    )

    counts["transcript_id"] = (
        counts["transcript_id"]
        .astype(str)
        .str.strip()
    )

    if counts["transcript_id"].duplicated().any():
        duplicated_ids = (
            counts.loc[
                counts["transcript_id"].duplicated(
                    keep=False
                ),
                "transcript_id"
            ]
            .drop_duplicates()
            .astype(str)
            .tolist()
        )

        examples = ", ".join(
            duplicated_ids[:10]
        )

        raise ValueError(
            "Transcript count matrix contains duplicated transcript IDs. "
            f"Examples: {examples}"
        )

    sample_columns = [
        column
        for column in counts.columns
        if column != "transcript_id"
    ]

    if not sample_columns:
        raise ValueError(
            "No sample count columns were found in the transcript "
            "count matrix."
        )

    for column in sample_columns:
        counts[column] = pd.to_numeric(
            counts[column],
            errors="raise"
        )

    annotated = mapping.merge(
        counts,
        on="transcript_id",
        how="right",
        validate="one_to_one"
    )

    missing_annotations = (
        annotated["aggregation_gene_id"]
        .isna()
    )

    missing_annotation_count = int(
        missing_annotations.sum()
    )

    if missing_annotation_count:
        print(
            f"Warning: {missing_annotation_count} transcripts did not "
            "have a matching annotation and will be excluded from "
            "gene-level aggregation."
        )

    annotated = annotated[
        [
            "transcript_id",
            "stringtie_gene_id",
            "ref_gene_id",
            "gene_name",
            "class_code",
            "aggregation_gene_id",
            *sample_columns
        ]
    ]

    annotated.to_csv(
        args.transcript_output,
        sep="\t",
        index=False,
        na_rep=""
    )

    gene_counts = (
        annotated
        .dropna(
            subset=["aggregation_gene_id"]
        )
        .groupby(
            "aggregation_gene_id",
            as_index=False
        )[sample_columns]
        .sum()
        .rename(
            columns={
                "aggregation_gene_id": "gene_id"
            }
        )
    )

    gene_counts.to_csv(
        args.gene_output,
        sep="\t",
        index=False
    )

    reference_gene_count = int(
        gene_counts["gene_id"]
        .astype(str)
        .str.startswith("ENSG")
        .sum()
    )

    novel_gene_count = int(
        gene_counts["gene_id"]
        .astype(str)
        .str.startswith("MSTRG.")
        .sum()
    )

    mapped_transcript_count = int(
        (
            mapping["aggregation_gene_id"]
            == mapping["ref_gene_id"]
        )
        .fillna(False)
        .sum()
    )

    retained_mstrg_transcript_count = int(
        mapping["aggregation_gene_id"]
        .astype("string")
        .str.startswith("MSTRG.")
        .fillna(False)
        .sum()
    )

    print(
        f"Transcript annotations read: {len(mapping)}"
    )

    print(
        f"Transcripts in count matrix: {len(counts)}"
    )

    print(
        "Transcripts mapped to reference ENSG IDs: "
        f"{mapped_transcript_count}"
    )

    print(
        "Transcripts retaining MSTRG gene IDs: "
        f"{retained_mstrg_transcript_count}"
    )

    print(
        f"Gene-level rows written: {len(gene_counts)}"
    )

    print(
        f"Reference ENSG rows: {reference_gene_count}"
    )

    print(
        f"Novel MSTRG rows: {novel_gene_count}"
    )


if __name__ == "__main__":
    main()
